/**
 * Order Module Definition
 *
 * Feature module for order management in E-Menum.
 * Provides order, table, zone, QR code, customer, and service request management.
 *
 * This is a FEATURE module - it can be enabled/disabled per organization.
 *
 * @module modules/order/order.module
 *
 * @example
 * ```typescript
 * import { OrderModule } from '@/modules/order/order.module';
 *
 * // Module is automatically discovered and loaded by ModuleLoader
 * // Access module instance via DI container
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
import type { ModuleInstance } from '@/core/kernel/module-loader';
import type { EventService } from '@/core/services/event.service';

import { OrderController } from '@/modules/order/order.controller';
import { OrderService } from '@/modules/order/order.service';
import { OrderRepository } from '@/modules/order/order.repository';
import { TableRepository } from '@/modules/order/table.repository';
import {
  orderRoutes,
  tableRoutes,
  zoneRoutes,
  qrcodeRoutes,
  customerRoutes,
  serviceRequestRoutes,
  feedbackRoutes,
} from '@/modules/order/order.routes';
import type { OrderModuleSettings } from '@/modules/order/order.types';

// -----------------------------------------------------------------------------
// Module Types
// -----------------------------------------------------------------------------

/**
 * Order module context for lifecycle hooks
 */
export interface OrderModuleContext {
  /** Event service for pub/sub */
  events: EventService;
  /** Module settings */
  settings: OrderModuleSettings;
  /** Logger function */
  log: (message: string) => void;
}

/**
 * Order module hook definitions
 */
export interface OrderModuleHooks {
  /** Called before order creation */
  beforeOrderCreate?: (data: { organizationId: string; tableId?: string }) => Promise<void>;
  /** Called after order creation */
  afterOrderCreate?: (data: { orderId: string; organizationId: string }) => Promise<void>;
  /** Called before status change */
  beforeStatusChange?: (data: {
    orderId: string;
    organizationId: string;
    currentStatus: string;
    targetStatus: string;
  }) => Promise<void>;
  /** Called after status change */
  afterStatusChange?: (data: {
    orderId: string;
    organizationId: string;
    previousStatus: string;
    newStatus: string;
  }) => Promise<void>;
  /** Called before item add */
  beforeItemAdd?: (data: { orderId: string; productId: string; organizationId: string }) => Promise<void>;
  /** Called after item add */
  afterItemAdd?: (data: { orderId: string; itemId: string; organizationId: string }) => Promise<void>;
  /** Called before table creation */
  beforeTableCreate?: (data: { organizationId: string; tableNumber: string }) => Promise<void>;
  /** Called after table creation */
  afterTableCreate?: (data: { tableId: string; organizationId: string }) => Promise<void>;
  /** Called before QR code generation */
  beforeQRCodeGenerate?: (data: { menuId: string; tableId?: string; organizationId: string }) => Promise<void>;
  /** Called after QR code generation */
  afterQRCodeGenerate?: (data: { qrCodeId: string; code: string; organizationId: string }) => Promise<void>;
}

// -----------------------------------------------------------------------------
// Order Module Class
// -----------------------------------------------------------------------------

/**
 * Order Module
 *
 * Feature module providing order management for E-Menum.
 * Handles orders, tables, zones, QR codes, customers, and service requests.
 *
 * Features:
 * - Order CRUD with status workflow
 * - Kitchen display integration
 * - Table and zone management
 * - QR code generation and tracking
 * - Customer management
 * - Service request handling
 * - Feedback collection
 *
 * @example
 * ```typescript
 * // Module is automatically loaded by ModuleLoader
 * // Use OrderService for business logic
 * const orderService = container.resolve('OrderService');
 * await orderService.create(orgId, { tableId: 'table_123', items: [...] });
 * ```
 */
@injectable()
export class OrderModule implements ModuleInstance {
  // ---------------------------------------------------------------------------
  // Static Properties
  // ---------------------------------------------------------------------------

  /** Module ID */
  static readonly id = 'order';

  /** Module name */
  static readonly name = 'Order Module';

  /** Module version */
  static readonly version = '1.0.0';

  /** Is core module (cannot be disabled) */
  static readonly isCore = false;

  /** Module type */
  static readonly type = 'feature';

  /** Module routes configuration */
  static readonly routes = {
    orders: orderRoutes,
    tables: tableRoutes,
    zones: zoneRoutes,
    qrcodes: qrcodeRoutes,
    customers: customerRoutes,
    serviceRequests: serviceRequestRoutes,
    feedback: feedbackRoutes,
  };

  /** Providers (services) to register */
  static readonly providers = [
    OrderService,
    OrderRepository,
    TableRepository,
  ];

  /** Controllers to register */
  static readonly controllers = [
    OrderController,
  ];

  /** Module dependencies */
  static readonly dependencies = {
    required: ['auth', 'organization', 'menu'],
    optional: ['notification'],
  };

  // ---------------------------------------------------------------------------
  // Instance Properties
  // ---------------------------------------------------------------------------

  /** Module hooks registry */
  private hooks: OrderModuleHooks = {};

  /** Module initialized flag */
  private initialized = false;

  constructor(
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // ModuleInstance Lifecycle Hooks
  // ---------------------------------------------------------------------------

  /**
   * Called when module is loaded.
   * Registers services with DI container.
   */
  async onLoad(): Promise<void> {
    this.log('Loading order module...');

    // Register repositories
    if (!appContainer.isRegistered('OrderRepository')) {
      registerSingleton('OrderRepository', OrderRepository);
    }
    if (!appContainer.isRegistered('TableRepository')) {
      registerSingleton('TableRepository', TableRepository);
    }

    // Register services
    if (!appContainer.isRegistered('OrderService')) {
      registerSingleton('OrderService', OrderService);
    }

    this.log('Order module loaded');
  }

  /**
   * Called when module is enabled/activated.
   * Sets up event listeners and registers routes.
   */
  async onEnable(): Promise<void> {
    if (this.initialized) {
      this.log('Order module already initialized');
      return;
    }

    this.log('Enabling order module...');

    // Subscribe to relevant events
    this.setupEventListeners();

    this.initialized = true;
    this.log('Order module enabled');

    // Emit module activated event
    await this.eventService.emitCustom('module.activated', {
      moduleId: OrderModule.id,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Called when module is disabled/deactivated.
   * Cleans up event listeners.
   */
  async onDisable(): Promise<void> {
    this.log('Disabling order module...');

    // Feature modules can be disabled
    // Clean up would happen here if needed

    this.initialized = false;
    this.log('Order module disabled');
  }

  /**
   * Called when module is unloaded.
   * Cleans up resources.
   */
  async onUnload(): Promise<void> {
    this.log('Unloading order module...');

    // Clear hooks
    this.hooks = {};

    this.log('Order module unloaded');
  }

  // ---------------------------------------------------------------------------
  // ModuleInstance Interface Methods
  // ---------------------------------------------------------------------------

  /**
   * Returns module routes for registration with Express.
   *
   * @returns Route configuration array
   */
  getRoutes(): unknown[] {
    return [OrderModule.routes];
  }

  /**
   * Returns module controllers for registration with routing-controllers.
   *
   * @returns Controller class array
   */
  getControllers(): unknown[] {
    return OrderModule.controllers;
  }

  // ---------------------------------------------------------------------------
  // Hook System
  // ---------------------------------------------------------------------------

  /**
   * Gets current module hooks.
   *
   * @returns Module hooks object
   */
  getHooks(): OrderModuleHooks {
    return { ...this.hooks };
  }

  /**
   * Registers a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handler - Hook handler function
   *
   * @example
   * ```typescript
   * orderModule.registerHook('afterOrderCreate', async (data) => {
   *   console.log('Order created:', data.orderId);
   * });
   * ```
   */
  registerHook<K extends keyof OrderModuleHooks>(
    hookName: K,
    handler: OrderModuleHooks[K]
  ): void {
    this.hooks[hookName] = handler;
    this.log(`Registered hook: ${hookName}`);
  }

  /**
   * Unregisters a hook handler.
   *
   * @param hookName - Name of the hook to unregister
   */
  unregisterHook(hookName: keyof OrderModuleHooks): void {
    delete this.hooks[hookName];
    this.log(`Unregistered hook: ${hookName}`);
  }

  /**
   * Executes a hook if registered.
   *
   * @param hookName - Name of the hook
   * @param data - Data to pass to the hook
   */
  async executeHook<K extends keyof OrderModuleHooks>(
    hookName: K,
    data: Parameters<NonNullable<OrderModuleHooks[K]>>[0]
  ): Promise<void> {
    const hook = this.hooks[hookName];
    if (hook) {
      try {
        await (hook as (data: typeof data) => Promise<void>)(data);
      } catch (error) {
        this.log(
          `Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`
        );
      }
    }
  }

  // ---------------------------------------------------------------------------
  // Event Listeners
  // ---------------------------------------------------------------------------

  /**
   * Sets up event listeners for the order module.
   */
  private setupEventListeners(): void {
    // Listen for organization deletion to clean up orders
    this.eventService.on('organization.deleted', async (payload) => {
      this.log(`Organization deleted event received: ${payload.organizationId}`);
      // Could trigger order cleanup for deleted organization
    });

    // Listen for menu publishing to trigger QR code updates
    this.eventService.on('menu.published', async (payload) => {
      this.log(`Menu published event received: ${payload.menuId}`);
      // Could update QR codes when menu is published
    });

    // Listen for subscription changes that may affect order limits
    this.eventService.on('subscription.plan.changed', async (payload) => {
      this.log(`Plan changed event received: ${payload.organizationId}`);
      // Could update order/table limits based on new plan
    });

    // Listen for product updates that may affect active orders
    this.eventService.on('product.updated', async (payload) => {
      this.log(`Product updated event received: ${payload.productId}`);
      // Could notify about product changes affecting pending orders
    });

    // Listen for product availability changes
    this.eventService.on('product.availability.changed', async (payload) => {
      this.log(`Product availability changed: ${payload.productId}`);
      // Could notify about unavailable products in pending orders
    });

    this.log('Event listeners set up');
  }

  // ---------------------------------------------------------------------------
  // Module Settings
  // ---------------------------------------------------------------------------

  /**
   * Gets default module settings.
   *
   * @returns Default order module settings
   */
  static getDefaultSettings(): OrderModuleSettings {
    return {
      defaultCurrency: 'TRY',
      orderNumberPrefix: 'ORD',
      autoCompleteDelayMinutes: 30,
      enableTableOrdering: true,
      enableTakeaway: true,
      enableDelivery: false,
      enableServiceRequests: true,
      requireCustomerInfo: false,
      enableFeedback: true,
      feedbackReminderDelayMinutes: 60,
      taxRate: 10,
      maxItemsPerOrder: 50,
      maxOrderNoteLength: 500,
    };
  }

  // ---------------------------------------------------------------------------
  // Utility Methods
  // ---------------------------------------------------------------------------

  /**
   * Logs a message with module prefix.
   *
   * @param message - Message to log
   */
  private log(message: string): void {
    // eslint-disable-next-line no-console
    console.log(`[OrderModule] ${message}`);
  }

  /**
   * Checks if module is initialized.
   *
   * @returns True if module is initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Gets module metadata.
   *
   * @returns Module metadata object
   */
  static getMetadata() {
    return {
      id: OrderModule.id,
      name: OrderModule.name,
      version: OrderModule.version,
      type: OrderModule.type,
      isCore: OrderModule.isCore,
      routes: OrderModule.routes,
      providers: OrderModule.providers.map((p) => p.name),
      controllers: OrderModule.controllers.map((c) => c.name),
      dependencies: OrderModule.dependencies,
    };
  }
}

// -----------------------------------------------------------------------------
// Module Exports
// -----------------------------------------------------------------------------

/**
 * Default export for module loader dynamic import
 */
export default OrderModule;

/**
 * Export module metadata
 */
export const metadata = OrderModule.getMetadata();
